import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  ResponsiveContainer,
} from "recharts";
import axios from "axios";
import {
  Code,
  ExternalLink,
  Sparkles,
  Trophy,
  Users,
  Heart,
  Target,
  Zap,
  Globe,
  BarChart2,
  Award,
  Shield,
  Flag,
  CheckCircle
} from "lucide-react";
import MasteryRadar from "./MasteryRadar";
import CareerCompass from "./CareerCompass";
import LivePulse from "./LivePulse";

/* ===================== TYPES ===================== */

interface Growth {
  date: string;
  score: number;
}

interface Recommendation {
  name: string;
  rating: number;
  tags: string[];
  link: string;
  reason: string;
  hint?: string;
}

export interface UserStats {
  platform: "codeforces" | "leetcode" | "codechef";
  handle: string;

  // Codeforces
  rating?: number;
  maxRating?: number;
  rank?: string;
  maxRank?: string;

  // LeetCode
  totalSolved?: number;
  easySolved?: number;
  mediumSolved?: number;
  hardSolved?: number;

  // CodeChef
  stars?: number;
  globalRank?: number;
  countryRank?: number;
  problemsSolved?: number;

  history: Growth[];
  cpulseRating?: number;

  // Rich Info
  avatar?: string;
  title?: string;
  contribution?: number;
  friendOfCount?: number;
  organization?: string;
  lastOnlineTimeSeconds?: number;
  contestRating?: number;
  globalRanking?: number;
  topPercentage?: number;
  reputation?: number;
  division?: string;
  country?: string;
}

/* ===================== COMPONENT ===================== */

export default function PersonalGrowth() {
  const { platform, username } = useParams<{
    platform: "codeforces" | "leetcode" | "codechef";
    username: string;
  }>();

  const [data, setData] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [classId, setClassId] = useState("");
  const [classMessage, setClassMessage] = useState("");

  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loadingRecs, setLoadingRecs] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);

  useEffect(() => {
    if (!username || !platform) {
      setError("Missing username or platform");
      setLoading(false);
      return;
    }

    setLoading(true);
    setError("");

    axios
      .get(`http://localhost:5000/user/${platform}/${username}/history`)
      .then((res: any) => {
        setData(res.data);
        setLoading(false);

        // Fetch Recommendations if platform is Codeforces
        if (platform === "codeforces") {
          setLoadingRecs(true);
          axios.get(`http://localhost:5000/api/recommend/${username}/${res.data.rating}`)
            .then(recRes => {
              setRecommendations(recRes.data.recommendations || []);
            })
            .catch(err => console.error("Recs Error:", err))
            .finally(() => setLoadingRecs(false));
        }

        // Fetch AI Analysis
        setLoadingAnalysis(true);
        axios.get(`http://localhost:5000/api/analysis/${platform}/${username}`)
          .then(res => setAiAnalysis(res.data))
          .catch(err => console.error("Analysis Error:", err))
          .finally(() => setLoadingAnalysis(false));
      })
      .catch((err) => {
        console.error("Stats Error:", err);
        if (err.response) {
          const msg = err.response.data.error || "Failed to fetch user data.";
          const details = err.response.data.details ? ` (${err.response.data.details})` : "";
          setError(msg + details);
        } else {
          setError("Unable to connect to server. Check your network.");
        }
        setLoading(false);
      });
  }, [username, platform]);

  /* ===================== LOADING ===================== */

  if (loading) {
    return (
      <div className="max-w-5xl mx-auto p-6">
        {/* LIVE PULSE FEED */}
        <LivePulse analysis={aiAnalysis} />

        <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="h-6 w-48 bg-gray-300 dark:bg-gray-700 rounded" />
          <div className="h-32 bg-gray-300 dark:bg-gray-700 rounded" />
          <div className="h-64 bg-gray-300 dark:bg-gray-700 rounded" />
        </div>
      </div>
    );
  }

  /* ===================== ERROR ===================== */

  if (error || !data) {
    return (
      <div className="max-w-xl mx-auto mt-20 bg-red-50 dark:bg-red-900/30 text-red-700 dark:text-red-300 p-6 rounded-xl text-center">
        <h2 className="text-lg font-semibold mb-2">
          Something went wrong
        </h2>
        <p className="text-sm">{error}</p>
      </div>
    );
  }

  /* ===================== UI ===================== */

  return (
    <div className="max-w-5xl mx-auto p-6 space-y-6">

      {/* ===================== EASTER EGG: GOD_ABHI ===================== */}
      {data.handle.toLowerCase() === "god_abhi" && data.platform === "leetcode" && (
        <div className="relative mb-10 text-center animate-bounce">
          <div className="inline-block relative">
            <Trophy size={64} className="text-yellow-400 drop-shadow-[0_0_15px_rgba(255,215,0,0.8)] mx-auto mb-2" />
            <div className="absolute -top-4 left-1/2 -translate-x-1/2 text-2xl">👑</div>
          </div>
          <h1 className="text-5xl font-black text-golden-gradient tracking-tighter uppercase">
            The Legendary Creator
          </h1>
          <p className="text-indigo-400 font-bold tracking-[0.3em] text-xs mt-2 uppercase">
            All Hail the Architect of CPulse
          </p>
        </div>
      )}

      {/* ============= HEADER / PROFILE ============= */}
      <div className={`
        bg-white dark:bg-gray-800 rounded-3xl shadow-2xl p-8 border-t-8 transition-all duration-700
        ${data.handle.toLowerCase() === "god_abhi" && data.platform === "leetcode"
          ? "border-yellow-400 animate-golden-glow ring-4 ring-yellow-400/20"
          : "border-indigo-500"}
      `}>
        <div className="flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-6">
            {/* UI Icon */}
            <div className="flex items-start gap-8">
              <div className="relative group">
                <div className={`p-1 rounded-3xl ${data.handle.toLowerCase() === "god_abhi" && data.platform === "leetcode" ? "bg-gradient-to-tr from-yellow-400 via-yellow-100 to-yellow-500 animate-golden-glow" : "bg-indigo-500/20"} shadow-2xl`}>
                  {data.avatar ? (
                    <img
                      src={data.avatar}
                      alt={data.handle}
                      className="w-24 h-24 rounded-2xl object-cover border-4 border-white dark:border-gray-800 shadow-xl"
                      onError={(e) => {
                        e.currentTarget.src = "https://cdn-icons-png.flaticon.com/512/149/149071.png";
                      }}
                    />
                  ) : (
                    <div className="w-24 h-24 bg-gray-100 dark:bg-gray-700 rounded-2xl flex items-center justify-center text-gray-400">
                      <Trophy size={48} />
                    </div>
                  )}
                  <div className="absolute -bottom-2 -right-2 p-1.5 bg-indigo-600 rounded-lg text-white shadow-lg border-2 border-white dark:border-gray-800">
                    <Sparkles size={14} />
                  </div>
                </div>
              </div>
              <div>
                <div className="flex items-center gap-3">
                  <h2 className={`text-5xl font-black tracking-tighter ${data.handle.toLowerCase() === "god_abhi" && data.platform === "leetcode" ? "text-golden-gradient" : "text-gray-900 dark:text-white"}`}>
                    {data.handle}
                  </h2>
                  {/* AI MASCOT / VIBE */}
                  {aiAnalysis && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-indigo-100 dark:bg-indigo-900/40 rounded-full animate-pulse border border-indigo-200 dark:border-indigo-800">
                      <Sparkles size={14} className="text-indigo-600 dark:text-indigo-400" />
                      <span className="text-[10px] font-black uppercase tracking-widest text-indigo-600 dark:text-indigo-400">
                        {aiAnalysis.vibe}
                      </span>
                    </div>
                  )}
                </div>

                <div className="flex flex-wrap items-center gap-3 text-gray-500 dark:text-gray-400 font-medium mt-2">
                  <div className="flex items-center gap-1.5 capitalize bg-gray-100 dark:bg-gray-700/50 px-3 py-1 rounded-full text-xs">
                    <Globe size={14} className="text-gray-400" />
                    {data.platform}
                  </div>
                  {data.country && (
                    <div className="flex items-center gap-1.5 bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 px-3 py-1 rounded-full text-xs border border-emerald-100 dark:border-emerald-800/50">
                      <Flag size={14} />
                      {data.country}
                    </div>
                  )}
                  {data.division && (
                    <div className="flex items-center gap-1.5 bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 px-3 py-1 rounded-full text-xs border border-purple-100 dark:border-purple-800/50">
                      <Shield size={14} />
                      {data.division}
                    </div>
                  )}
                </div>
                <p className="text-sm text-indigo-500 font-black uppercase tracking-[0.3em] mt-1">
                  {data.title || `${data.platform} Professional`}
                </p>

                {/* AI BIO */}
                {aiAnalysis && (
                  <div className="mt-4 max-w-lg">
                    <p className="text-sm text-gray-600 dark:text-gray-300 italic font-medium leading-relaxed border-l-2 border-indigo-500 pl-4 py-1 bg-indigo-50/30 dark:bg-indigo-900/10 rounded-r-xl">
                      {aiAnalysis.bio}
                    </p>
                    <p className="text-[10px] font-bold text-indigo-400 mt-2 uppercase tracking-widest">
                      "{aiAnalysis.vibeQuote}"
                    </p>
                  </div>
                )}
              </div>
            </div>

            <div className="flex flex-col items-end">
              <div className={`
                text-3xl font-black px-6 py-3 rounded-2xl shadow-lg transition-transform
                ${data.handle.toLowerCase() === "god_abhi" && data.platform === "leetcode"
                  ? "bg-yellow-400 text-black scale-110 shadow-yellow-400/50"
                  : "bg-indigo-600 text-white"}
            `}>
                {data.platform === "codeforces" || data.platform === "codechef" ? data.rating : data.cpulseRating}
              </div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-2">Current Pulse Rating</p>
            </div>
          </div>

          {/* QUICK ACTIONS / ADD TO CLASS */}
          <div className="mt-8 p-4 bg-indigo-50 dark:bg-indigo-900/10 border border-indigo-100 dark:border-indigo-800/50 rounded-2xl flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-white dark:bg-gray-800 rounded-lg shadow-sm text-indigo-600">
                <Users size={20} />
              </div>
              <div>
                <h4 className="text-sm font-bold text-gray-900 dark:text-white">Community & Class</h4>
                <p className="text-xs text-gray-500">Add this profile to your college class or group</p>
              </div>
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <input
                value={classId}
                onChange={(e) => setClassId(e.target.value)}
                placeholder="Enter class (e.g. CS-A)"
                className="flex-1 md:w-48 px-3 py-2 text-sm border rounded-lg dark:bg-gray-800 dark:border-gray-700"
              />
              <button
                onClick={() => {
                  if (!classId) return;
                  axios.post(`/api/users/class`, {
                    handle: data.handle,
                    platform: data.platform,
                    classId
                  }).then(() => {
                    setClassMessage(`Added to ${classId}!`);
                    setTimeout(() => setClassMessage(""), 3000);
                  }).catch(() => {
                    setClassMessage("Failed to add.");
                    setTimeout(() => setClassMessage(""), 3000);
                  });
                }}
                className="px-4 py-2 bg-indigo-600 text-white text-sm font-bold rounded-lg hover:bg-indigo-700 transition shadow-lg"
              >
                Add
              </button>
            </div>
            {classMessage && (
              <p className="absolute -bottom-6 right-4 text-[10px] font-bold text-indigo-600 animate-bounce">
                {classMessage}
              </p>
            )}
          </div>

          {/* ===================== RICH STATS GRID ===================== */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mt-8 pt-8 border-t border-gray-100 dark:border-gray-800/50">
            {data.platform === "codeforces" && (
              <>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Users size={12} /> Contribution
                  </p>
                  <p className={`text-lg font-bold ${data.contribution && data.contribution > 0 ? 'text-emerald-500' : 'text-gray-500'}`}>
                    {data.contribution || 0}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Heart size={12} /> Friends
                  </p>
                  <p className="text-lg font-bold text-gray-900 dark:text-white">
                    {data.friendOfCount || 0}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Target size={12} /> Organization
                  </p>
                  <p className="text-[11px] font-bold text-gray-700 dark:text-gray-300 truncate">
                    {data.organization || "Independent"}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Zap size={12} /> Last Online
                  </p>
                  <p className="text-[11px] font-bold text-gray-500">
                    {data.lastOnlineTimeSeconds ? new Date(data.lastOnlineTimeSeconds * 1000).toLocaleDateString() : 'Unknown'}
                  </p>
                </div>
              </>
            )}

            {data.platform === "leetcode" && (
              <>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Trophy size={12} /> Contest Rating
                  </p>
                  <p className="text-lg font-bold text-indigo-600 dark:text-indigo-400">
                    {data.contestRating || 'Unrated'}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Globe size={12} /> Global Rank
                  </p>
                  <p className="text-lg font-bold text-gray-900 dark:text-white">
                    #{data.globalRanking?.toLocaleString() || 'N/A'}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Award size={12} /> Reputation
                  </p>
                  <p className="text-lg font-bold text-gray-900 dark:text-white">
                    {data.reputation || 0}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <BarChart2 size={12} /> Top %
                  </p>
                  <p className="text-lg font-bold text-emerald-500">
                    {data.topPercentage ? `${data.topPercentage.toFixed(2)}%` : 'N/A'}
                  </p>
                </div>
              </>
            )}

            {data.platform === "codechef" && (
              <>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Shield size={12} /> Division
                  </p>
                  <p className="text-lg font-bold text-indigo-600 dark:text-indigo-400">
                    {data.division || "Div ?"}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Globe size={12} /> Global Rank
                  </p>
                  <p className="text-lg font-bold text-gray-900 dark:text-white">
                    #{data.globalRank?.toLocaleString() || 'N/A'}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Flag size={12} /> Country Rank
                  </p>
                  <p className="text-lg font-bold text-gray-900 dark:text-white">
                    #{data.countryRank?.toLocaleString() || 'N/A'}
                  </p>
                </div>
                <div className="bg-gray-50/50 dark:bg-gray-900/40 p-4 rounded-2xl border border-gray-100 dark:border-gray-800/50">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 flex items-center gap-2">
                    <CheckCircle size={12} /> Solved
                  </p>
                  <p className="text-lg font-bold text-emerald-500">
                    {data.problemsSolved || 0}
                  </p>
                </div>
              </>
            )}
          </div>
        </div>

        {/* RECOMMENDATIONS (If Codeforces) */}
        {platform === "codeforces" && (
          <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl shadow-xl p-6 text-white">
            <div className="flex items-center gap-2 mb-4">
              <Sparkles size={24} className="text-yellow-300" />
              <h3 className="text-xl font-bold">AI Recommended Challenges</h3>
            </div>

            {loadingRecs ? (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-pulse">
                {[1, 2, 3].map(i => <div key={i} className="h-40 bg-white/20 rounded-xl"></div>)}
              </div>
            ) : recommendations.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {recommendations.map((rec: Recommendation, i: number) => (
                  <div key={i} className="bg-white/10 backdrop-blur-sm border border-white/20 p-5 rounded-xl flex flex-col justify-between hover:bg-white/20 transition group">
                    <div>
                      <div className="flex justify-between items-start mb-2">
                        <span className="bg-yellow-400 text-black text-[10px] font-black px-2 py-0.5 rounded uppercase">
                          Rating {rec.rating}
                        </span>
                        <Trophy size={16} className="text-indigo-200" />
                      </div>
                      <h4 className="font-bold text-lg mb-2 line-clamp-1">{rec.name}</h4>
                      <p className="text-xs text-indigo-100 mb-4 line-clamp-3 italic opacity-80">"{rec.reason}"</p>
                    </div>

                    <div className="flex flex-wrap gap-1 mb-4">
                      {rec.tags.slice(0, 3).map(tag => (
                        <span key={tag} className="text-[10px] bg-indigo-500/50 px-2 py-1 rounded-md">{tag}</span>
                      ))}
                    </div>

                    <div className="flex flex-col gap-2">
                      <a
                        href={rec.link}
                        target="_blank"
                        rel="noreferrer"
                        className="w-full py-2 bg-white text-indigo-600 font-bold rounded-lg text-center text-sm flex items-center justify-center gap-2 hover:bg-indigo-50 shadow-lg"
                      >
                        Solve Now <ExternalLink size={14} />
                      </a>

                      {/* SMART HINT */}
                      {rec.hint && (
                        <div className="mt-2 group/hint">
                          <button
                            onClick={(e) => {
                              const el = e.currentTarget.nextElementSibling as HTMLElement;
                              el.classList.toggle('hidden');
                              e.currentTarget.classList.toggle('bg-indigo-500/20');
                            }}
                            className="w-full py-1.5 bg-indigo-500/10 text-indigo-400 text-[10px] font-black uppercase tracking-widest rounded-lg hover:bg-indigo-500/20 transition-colors flex items-center justify-center gap-2"
                          >
                            <Sparkles size={10} /> Get AI Hint
                          </button>
                          <div className="hidden mt-2 p-3 bg-indigo-900/40 border border-indigo-400/20 rounded-xl text-[11px] leading-relaxed text-indigo-100 animate-in fade-in slide-in-from-top-1 duration-300">
                            {rec.hint}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-indigo-100 text-sm">No specific challenges found. Keep grinding!</p>
            )}
          </div>
        )}

        {classMessage && (
          <p className="text-sm text-center text-green-600 dark:text-green-400">
            {classMessage}
          </p>
        )}


        {/* ===================== STATS ===================== */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {data.platform === "codeforces" && (
            <>
              <Stat label="Rating" value={data.rating} />
              <Stat label="Max Rating" value={data.maxRating} />
              <Stat label="Rank" value={data.rank} />
              <Stat label="Max Rank" value={data.maxRank} />
            </>
          )}

          {data.platform === "leetcode" && (
            <>
              <Stat label="Total Solved" value={data.totalSolved} />
              <Stat label="Easy" value={data.easySolved} />
              <Stat label="Medium" value={data.mediumSolved} />
              <Stat label="Hard" value={data.hardSolved} />
            </>
          )}

          {data.platform === "codechef" && (
            <>
              <Stat label="Current Rating" value={data.rating} />
              <Stat label="Max Rating" value={data.maxRating} />
              <Stat label="Stars" value={`${data.stars || 0}★`} />
              <Stat label="Global Rank" value={data.globalRank} />
              <Stat label="Country Rank" value={data.countryRank} />
              <Stat label="Problems Solved" value={data.problemsSolved} />
            </>
          )}
        </div>

        {/* ===================== GROWTH CHART ===================== */}
        {data.history?.length > 0 && (
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow p-6">
            <h3 className="text-lg font-semibold mb-4">
              Rating / Score Progress
            </h3>

            <ResponsiveContainer width="100%" height={350}>
              <LineChart data={data.history}>
                <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.2} />
                <XAxis dataKey="date" />
                <YAxis allowDecimals={false} />
                <Tooltip />
                <Line
                  type="monotone"
                  dataKey="score"
                  stroke="#6366f1"
                  strokeWidth={3}
                  dot={false}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        )}

        {/* ===================== CAREER COMPASS ===================== */}
        <CareerCompass
          score={data.cpulseRating || 0}
          aiAdvice={aiAnalysis?.roadmapTip}
        />

        {/* ===================== CLEAN CODE TIP ===================== */}
        {aiAnalysis?.cleanCodeTip && (
          <div className="bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-800 rounded-3xl p-6 flex items-start gap-4">
            <div className="p-3 bg-white dark:bg-gray-800 rounded-2xl shadow-sm text-emerald-600">
              <Code size={24} />
            </div>
            <div>
              <h4 className="text-sm font-black uppercase text-emerald-600 dark:text-emerald-400 tracking-widest mb-1">AI Performance Insight</h4>
              <p className="text-sm text-gray-700 dark:text-gray-300 font-medium italic">
                "{aiAnalysis.cleanCodeTip}"
              </p>
            </div>
          </div>
        )}
        {data.history?.length === 0 && (
          <div className="text-center text-gray-500 dark:text-gray-400 mt-8">
            <p className="text-sm">
              No growth data yet. Stats shown above are current.
            </p>
          </div>
        )}
      </div>
    </div >
  );
}

/* ===================== STAT CARD ===================== */

function Stat({ label, value }: { label: string; value: any }) {
  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 text-center">
      <p className="text-xs text-gray-500">{label}</p>
      <p className="text-xl font-semibold">{value ?? "N/A"}</p>
    </div>
  );
}
